var value = form.data.created_at;
var formatted = value;

try {
    var date;

    if (value instanceof Date) {
        date = value;
    } else if (typeof value === 'string') {
        // Parse ISO string and handle 'Z' timezone indicator
        var isoString = value.replace('Z', '+00:00');
        date = new Date(isoString);
    }

    if (date && !isNaN(date.getTime())) {
        // Convert UTC to IST (UTC+5:30)
        var istOffset = 5.5 * 60 * 60 * 1000; // 5 hours 30 minutes in milliseconds
        var istDate = new Date(date.getTime() + istOffset);

        var months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
                     'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

        var month = months[istDate.getUTCMonth()];
        var day = istDate.getUTCDate();
        var year = istDate.getUTCFullYear();

        var hours = istDate.getUTCHours();
        var minutes = istDate.getUTCMinutes();
        var ampm = hours >= 12 ? 'PM' : 'AM';

        hours = hours % 12;
        hours = hours ? hours : 12;

        var minutesStr = minutes < 10 ? '0' + minutes : minutes;

        // Format: "Apr 24, 2025 - 11:32 AM" (matches backend)
        formatted = month + ' ' + day + ', ' + year + ' - ' + hours + ':' + minutesStr + ' ' + ampm;
    }
} catch (e) {
    // Return original value on error
}
return "Date: " + formatted;

